class Dog {
  // These are Attributes (the State)
  String name;
  int age;
  boolean isGoodBoy = true;
}

class Main {
  public static void main(String[] args) {
    Dog myDog = new Dog(); // Builds a dog
    myDog.name = "Rex";    // Uses the '.' to access its attributes
    myDog.age = 3;         // Ages Rex 3 years

    System.out.println(myDog.name + " is " + myDog.age);
  }
}

class Dog {
  String name;
}

class Main {
